parameters.jsCode:
// Parse AI output safely and merge back into lead
const raw = $input.first().json;
let parsed = raw;

// OpenAI node returns either {message:{content}} or direct json
if (raw && raw.message && raw.message.content) {
  try { parsed = typeof raw.message.content === 'string' ? JSON.parse(raw.message.content) : raw.message.content; }
  catch (e) { parsed = { fit_score: 0, tier: 'D', reasoning: 'Parse error: '+e.message, pain_hypothesis: '' }; }
}

// Merge with original lead from upstream
const lead = $('When Executed by Parent').item.json;

return [{ json: { ...lead, ...parsed } }];
